/**
 * @summary Search visible locations
 */
export const getSearchLocationsUrl = (params?: SearchLocationsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/locations/search?${stringifiedParams}`
    : `/api/locations/search`;
};

export const searchLocations = async (
  params?: SearchLocationsParams,
  options?: RequestInit,
): Promise<SearchLocations200> => {
  return customFetch<SearchLocations200>(getSearchLocationsUrl(params), {
    ...options,
    method: "GET",
  });
};

